// Import the functions you need from the SDKs you need
import { initializeApp, getApps } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore } from "firebase/firestore";

// Your web app's Firebase configuration
const firebaseConfig = {
  apiKey: "AIzaSyDGXe1QNhLNxm3LKwGvpQyOGTDpOxXuMPc",
  authDomain: "careafrica-d2d6d.firebaseapp.com",
  projectId: "careafrica-d2d6d",
  storageBucket: "careafrica-d2d6d.appspot.com",
  messagingSenderId: "1098765432",
  appId: "1:1098765432:web:abc123def456"
};

// Initialize Firebase only if it hasn't been initialized yet
let app;
if (!getApps().length) {
  app = initializeApp(firebaseConfig);
} else {
  app = getApps()[0];
}

// Initialize Firebase Authentication and get a reference to the service
export const auth = getAuth(app);

// Initialize Cloud Firestore and get a reference to the service
export const firestore = getFirestore(app);

export default app;
